import React, { useState,useEffect } from "react";
import "./style.css";
import { useNavigate } from "react-router-dom";



function Recommendation(){

    const [carbs,setCarbs]=useState(0);
    const [calories,setCalories]=useState(0);

    async function handlePage() {
        try{
            const response=await fetch('http://localhost:5000/recommendation');
            const data=await response.json();
            console.log(data);
            setCalories(data[0].calories||0);
            setCarbs(data[0].carbs||0);
        }
        catch(err){
            console.log(err.message);
        }
    }
            
    useEffect(()=>{handlePage()},[]);

    return (
        <>
            <div>
                <h2>Total Carbs consumed today is {carbs}</h2>
                <h2>Total Calories consumed today is {calories}</h2>

            </div>
        </>
    )
}

export default Recommendation;
